def sina_xml_to_url_list(xml_data):
    """
    Convert XML data containing <durl><url>...</url></durl> entries into a list of URL strings.
    Returns an empty list on parse errors or if no URLs are found.
    """
    from xml.dom.minidom import parseString, Node

    try:
        dom = parseString(xml_data)
    except Exception:
        return []

    urls = []
    for durl in dom.getElementsByTagName('durl'):
        url_nodes = durl.getElementsByTagName('url')
        if not url_nodes:
            continue
        first_url = url_nodes[0]

        # Collect all text content from the first <url> element, ignoring non-text nodes
        text_parts = []
        for node in first_url.childNodes:
            if getattr(node, 'nodeType', None) == Node.TEXT_NODE:
                text_parts.append(node.data)
        url_text = ''.join(text_parts).strip()

        if url_text:
            urls.append(url_text)

    return urls
